    "consequential_damages_excluded": false,
    "concerns": [
      "Complete unlimited liability for all claim types",
      "Single incident could expose company to catastrophic losses",
      "No protection against customer's consequential damages or lost profits",
      "Liability could far exceed contract value and insurance coverage"
    ]
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 95,
    "red_flags": [
      {
        "category": "Liability",
        "severity": "critical",
        "issue": "Unlimited liability for ALL claims with no cap or exclusions",
        "detail": "This contract exposes our company to unlimited financial liability for any failure. If we experience a service outage, security breach, or data loss, customer could sue for unlimited damages including their consequential damages and lost profits. This single contract could threaten the entire company's financial viability.",
        "recommendation": "REJECT this clause. NEGOTIATE: 12 months of fees general cap with unlimited liability ONLY for (1) security breach due to our gross negligence, (2) our willful misconduct, (3) IP infringement. Must add exclusion of consequential damages.",
        "business_impact": "Company bankruptcy risk - single claim could exceed all assets and insurance coverage"
      }
    ]
  }
}

{
