{
  "payment_terms": {
    "summary": "Net 90 payment terms with withholding rights for disputes and payment upon acceptance",
    "payment_schedule": "Upon acceptance of deliverables",
    "payment_terms": "Net 90 days",
    "withholding_rights": "Customer can withhold payment for any disputed amounts (not limited to billing disputes)",
    "revenue_recognition_risk": "Payment contingent on customer acceptance - may delay revenue recognition",
    "concerns": [
      "Net 90 is extended payment terms (standard is Net 30-45) - cash flow impact",
      "Customer can withhold for 'any disputed amounts' (not just billing disputes)",
      "Payment contingent on acceptance with subjective 'unreasonably withheld' standard",
      "Could delay revenue recognition if acceptance is delayed"
    ]
  },
  "risk_assessment": {
    "overall_risk_level": "medium",
    "yellow_flags": [
      {
        "category": "Payment",
        "issue": "Extended payment terms (Net 90) with broad withholding rights",
        "detail": "Net 90 creates cash flow challenges, especially for smaller contracts. Customer's ability to withhold payment for 'any disputed amounts' is too broad - could withhold for non-billing disputes (e.g., service quality disputes). Payment contingent on acceptance could delay revenue if customer is slow to accept or uses acceptance as negotiation leverage.",
        "recommendation": "NEGOTIATE: (1) Reduce to Net 45 or Net 60, (2) Limit withholding to 'disputed invoiced amounts' (not any dispute), (3) Add objective acceptance criteria or automatic acceptance if no rejection within 10 business days",
        "clause_reference": "Section 6.1"
      }
    ]
  }
}
